from abc import ABC, abstractmethod
from threading import Lock
from typing import Protocol
import random


class Server:
    def __init__(self, server_id: str, address: str):
        self.server_id = server_id
        self.address = address

    def __eq__(self, other: object) -> bool:
        if not isinstance(other, Server):
            return False
        return self.address == other.address

    def __hash__(self) -> int:
        return hash(self.address)


class LoadBalancingStrategy(Protocol):
    def select(self, servers: list[Server]) -> Server: ...
    def reset(self) -> None: ...


class RandomStrategy:
    def select(self, servers: list[Server]) -> Server:
        return random.choice(servers)

    def reset(self) -> None:
        pass


class RoundRobinStrategy:
    def __init__(self):
        self._index = 0
        self._lock = Lock()

    def select(self, servers: list[Server]) -> Server:
        with self._lock:
            server = servers[self._index % len(servers)]
            self._index += 1
            return server

    def reset(self) -> None:
        with self._lock:
            self._index = 0


class LoadBalancerFullError(Exception):
    pass


class ServerAlreadyRegisteredError(Exception):
    pass


class NoServersAvailableError(Exception):
    pass


class LoadBalancer:
    MAX_SERVERS = 10

    def __init__(self, strategy: LoadBalancingStrategy | None = None):
        self._servers: list[Server] = []
        self._addresses: set[str] = set()
        self._strategy = strategy or RandomStrategy()
        self._lock = Lock()

    def register(self, server: Server) -> None:
        with self._lock:
            if len(self._servers) >= self.MAX_SERVERS:
                raise LoadBalancerFullError(f"Cannot exceed {self.MAX_SERVERS} servers")
            if server.address in self._addresses:
                raise ServerAlreadyRegisteredError(f"Server {server.address} already registered")
            self._servers.append(server)
            self._addresses.add(server.address)

    def deregister(self, server: Server) -> None:
        with self._lock:
            if server.address not in self._addresses:
                return
            self._servers = [s for s in self._servers if s.address != server.address]
            self._addresses.remove(server.address)
            self._strategy.reset()

    def get(self) -> Server:
        with self._lock:
            if not self._servers:
                raise NoServersAvailableError("No servers registered")
            return self._strategy.select(list(self._servers))

    @property
    def server_count(self) -> int:
        with self._lock:
            return len(self._servers)

from threading import Lock
import random
import string


class UrlShortenerFullError(Exception):
    pass


class UrlNotFoundError(Exception):
    pass


class UrlShortener:
    MAX_URLS = 100
    SHORT_URL_LENGTH = 6

    def __init__(self):
        self._url_to_short: dict[str, str] = {}
        self._short_to_url: dict[str, str] = {}
        self._lock = Lock()

    def shorten(self, url: str) -> str:
        with self._lock:
            if url in self._url_to_short:
                return self._url_to_short[url]

            if len(self._url_to_short) >= self.MAX_URLS:
                raise UrlShortenerFullError(f"Cannot exceed {self.MAX_URLS} URLs")

            short_url = self._generate_short_url()
            while short_url in self._short_to_url:
                short_url = self._generate_short_url()

            self._url_to_short[url] = short_url
            self._short_to_url[short_url] = url
            return short_url

    def resolve(self, short_url: str) -> str:
        with self._lock:
            if short_url not in self._short_to_url:
                raise UrlNotFoundError(f"Short URL {short_url} not found")
            return self._short_to_url[short_url]

    def _generate_short_url(self) -> str:
        chars = string.ascii_letters + string.digits
        return ''.join(random.choice(chars) for _ in range(self.SHORT_URL_LENGTH))

    @property
    def url_count(self) -> int:
        with self._lock:
            return len(self._url_to_short)

from threading import Lock
from decimal import Decimal
from typing import Dict


class InsufficientFundsError(Exception):
    pass


class AccountNotFoundError(Exception):
    pass


class InvalidAmountError(Exception):
    pass


class Account:
    def __init__(self, account_id: str, initial_balance: Decimal):
        self.account_id = account_id
        self._balance = initial_balance
        self._lock = Lock()

    @property
    def balance(self) -> Decimal:
        with self._lock:
            return self._balance


class TransferService:
    def __init__(self):
        self._accounts: Dict[str, Account] = {}
        self._global_lock = Lock()

    def create_account(self, account_id: str, initial_balance: Decimal) -> Account:
        with self._global_lock:
            if account_id in self._accounts:
                raise ValueError(f"Account {account_id} already exists")
            account = Account(account_id, initial_balance)
            self._accounts[account_id] = account
            return account

    def transfer(self, from_account_id: str, to_account_id: str, amount: Decimal) -> None:
        if amount <= 0:
            raise InvalidAmountError("Transfer amount must be positive")

        from_account = self._accounts[from_account_id]
        to_account = self._accounts[to_account_id]

        # Consistent lock ordering to prevent deadlock
        first, second = sorted([from_account, to_account], key=lambda a: a.account_id)

        with first._lock:
            with second._lock:
                if from_account._balance < amount:
                    raise InsufficientFundsError(f"Insufficient funds")
                from_account._balance -= amount
                to_account._balance += amount
